    20→namespace Microsoft.ML.Tokenizers
    21→{
    22→    /// <summary>
    23→    /// Represent the rapid Byte Pair Encoding tokenizer.
    24→    /// </summary>
    25→    public sealed partial class TiktokenTokenizer : Tokenizer
    26→    {
    27→        private readonly Dictionary<ReadOnlyMemory<byte>, int> _encoder;
    28→        private readonly Dictionary<int, ReadOnlyMemory<byte>> _decoder;
    29→        private readonly LruCache<(int Id, int TokenIndex, int TokenLength)[]> _cache;
    30→        private readonly Dictionary<StringSpanOrdinalKey, (int Id, string Token)> _vocab;
    31→        private IReadOnlyDictionary<string, int>? _vocabOriginal;
    32→        private const int MaxWordLengthToCache = 15;
    33→        private readonly PreTokenizer? _preTokenizer;
    34→        private readonly Normalizer? _normalizer;
    35→
    36→        /// <summary>
    37→        /// Create a new Tiktoken tokenizer's object.
    38→        /// </summary>
    39→        /// <param name="vocabFilePath">The path to the BPE vocab file.</param>
    40→        /// <param name="preTokenizer">The pre-tokenizer to use.</param>
    41→        /// <param name="specialTokens">The dictionary mapping special tokens to Ids.</param>
    42→        /// <param name="normalizer">The normalizer to use.</param>
    43→        /// <param name="cacheSize">The size of the cache to use.</param>
    44→        /// <exception cref="ArgumentNullException">Thrown when <paramref name="vocabFilePath"/> is null or empty.</exception>
    45→        /// <exception cref="InvalidOperationException">Thrown when failed to load the BPE vocab file.</exception>
    46→        internal TiktokenTokenizer(string vocabFilePath, PreTokenizer? preTokenizer, IReadOnlyDictionary<string, int>? specialTokens = null, Normalizer? normalizer = null, int cacheSize = LruCache<int[]>.DefaultCacheSize) :
    47→            this(string.IsNullOrEmpty(vocabFilePath) ? throw new ArgumentNullException(nameof(vocabFilePath)) : File.OpenRead(vocabFilePath), preTokenizer, specialTokens, normalizer, cacheSize, disposeStream: true)
    48→        {
    49→        }
    50→
    51→        /// <summary>
    52→        /// Create a new Tiktoken tokenizer's object.
    53→        /// </summary>
    54→        /// <param name="vocabStream">The stream to the BPE vocab file.</param>
    55→        /// <param name="preTokenizer">The pre-tokenizer to use.</param>
    56→        /// <param name="specialTokens">The dictionary mapping special tokens to Ids.</param>
    57→        /// <param name="normalizer">The normalizer to use.</param>
    58→        /// <param name="cacheSize">The size of the cache to use.</param>
    59→        /// <exception cref="ArgumentNullException">Thrown when <paramref name="vocabStream"/> is null or empty.</exception>
