   464→        private int EncodeToIdsResult((int Id, int TokenIndex, int TokenLength)[] tokens, IList<int>? accumulatedIds, int maxTokens, int fullTextLength, out int charsConsumed)
   465→        {
   466→            charsConsumed = 0;
   467→
   468→            if (tokens.Length <= maxTokens)
   469→            {
   470→                if (accumulatedIds is not null)
   471→                {
   472→                    foreach (var t in tokens)
   473→                    {
   474→                        accumulatedIds.Add(t.Id);
   475→                    }
   476→                }
   477→
   478→                charsConsumed = fullTextLength;
   479→                return tokens.Length;
   480→            }
   481→
   482→            int tokenCount;
   483→            for (tokenCount = 0; tokenCount < maxTokens; tokenCount++)
   484→            {
   485→                int overlapIndex = tokens[tokenCount].TokenIndex + tokens[tokenCount].TokenLength;
   486→                // maxTokens is less than tokens.Count, so it is safe to index maxTokens.
   487→                if (tokens[tokenCount + 1].TokenIndex < overlapIndex)
   488→                {
   489→                    // Ensure we'll not break the text in the middle of a code-point
   490→                    int j = tokenCount + 2;
   491→                    while (j < tokens.Length && tokens[j].TokenIndex < overlapIndex)
   492→                    {
   493→                        j++;
   494→                    }
   495→
   496→                    if (j <= maxTokens)
   497→                    {
   498→                        // append encountered tokens to the accumulatedIds
   499→                        for (int k = tokenCount; k < j; k++)
   500→                        {
   501→                            accumulatedIds?.Add(tokens[k].Id);
   502→                        }
   503→                        tokenCount = j - 1;
   504→                        charsConsumed = tokens[tokenCount].TokenIndex + tokens[tokenCount].TokenLength;
   505→                    }
   506→                    else
   507→                    {
   508→                        break;
   509→                    }
   510→                }
   511→                else
   512→                {
   513→                    accumulatedIds?.Add(tokens[tokenCount].Id);
   514→                    charsConsumed = tokens[tokenCount].TokenIndex + tokens[tokenCount].TokenLength;
   515→                }
   516→            }
   517→
   518→            return tokenCount;
   519→        }
