   760→            {
   761→                if (accumulatedIds is not null)
   762→                {
   763→                    foreach (var t in tokens)
   764→                    {
   765→                        accumulatedIds.Add(t.Id);
   766→                    }
   767                }
   768→
   769→                textIndex = 0;
   770→                return tokens.Length;
   771→            }
   772→
   773→            int index = tokens.Length - maxTokens;
   774→
   775→            // avoid breaking the text in the middle of a code-point
   776→            while (index < tokens.Length && tokens[index].TokenIndex < tokens[index - 1].TokenIndex + tokens[index - 1].TokenLength)
