   790→        /// <summary>
   791→        /// Decode the given ids, back to a String.
   792→        /// </summary>
   793→        /// <param name="ids">The list of ids that we want to decode.</param>
   794→        /// <returns>The decoded string.</returns>
   795→        public override string Decode(IEnumerable<int> ids)
   796→        {
   797→            // Tiktoken doesn't guarantee a one-to-one correspondence between IDs and UTF-16 words.
   798→            // Consequently, decoding individual IDs into UTF-16 string is not supported; instead, decoding all IDs must be performed collectively.
   799→            // Here's an example case that maps one character to multiple IDs:
   800→            // '⭐' U-2B50 is mapped to IDs [2928, 99834] in the Tiktoken model.
   801→            // In other words, the character '⭐' with UTF-8 code point 0xE2, 0xAD, 0x90 will be mapped by Tiktoken as follows: 0xE2 to [2928]
   802→            // and 0xAD, 0x90 to [99834]. Decoding 2928 and 99834 individually won't reconstruct the original UTF-16 string '⭐' U-2B50;
   803→            // decoding all IDs together is required to get the expected result.
   804→            if (ids is null)
   805→            {
   806→                throw new ArgumentNullException(nameof(ids));
   807→            }
   808→
   809→            byte[]? arrayPoolArray = null;
   810→            try
   811→            {
   812→                Span<byte> utf8Bytes = stackalloc byte[256];
   813→                int utf8ByteCount = 0;
   814→
   815→                foreach (int id in ids)
   816→                {
   817→                    if (_decoder.TryGetValue(id, out ReadOnlyMemory<byte> tokenBytes))
   818→                    {
   819→                        if ((uint)utf8ByteCount + (uint)tokenBytes.Length > (uint)utf8Bytes.Length)
   820→                        {
   821→                            ArrayPoolGrow(ref utf8Bytes, ref arrayPoolArray, utf8ByteCount + tokenBytes.Length);
   822→                        }
   823→
   824→                        tokenBytes.Span.CopyTo(utf8Bytes.Slice(utf8ByteCount));
   825→                        utf8ByteCount += tokenBytes.Length;
   826→                    }
   827→                }
   828→
   829→                return Helpers.GetString(utf8Bytes.Slice(0, utf8ByteCount));
   830→            }
   831→            finally
   832→            {
   833→                if (arrayPoolArray is not null)
   834→                {
   835→                    ArrayPool<byte>.Shared.Return(arrayPoolArray);
   836→                }
   837→            }
   838→
   839→            static void ArrayPoolGrow(ref Span<byte> utf8Bytes, ref byte[]? arrayPoolArray, int requiredCapacity)
   840→            {
   841→                byte[] tmp = ArrayPool<byte>.Shared.Rent(Math.Max(utf8Bytes.Length * 2, requiredCapacity));
   842→                utf8Bytes.CopyTo(tmp.AsSpan());
   843→                byte[]? toReturn = arrayPoolArray;
   844→                utf8Bytes = arrayPoolArray = tmp;
   845→                if (toReturn is not null)
   846→                {
   847→                    ArrayPool<byte>.Shared.Return(toReturn);
   848→                }
   849→            }
   850→        }
