   864→
   865→            // Tiktoken doesn't guarantee a one-to-one correspondence between IDs and UTF-16 words.
   866→            // Consequently, decoding individual IDs into UTF-16 string is not supported; instead, decoding all IDs must be performed collectively.
   867→            // Here's an example case that maps one character to multiple IDs:
   868→            // '⭐' U-2B50 is mapped to IDs [2928, 99834] in the Tiktoken model.
   869→            // In other words, the character '⭐' with UTF-8 code point 0xE2, 0xAD, 0x90 will be mapped by Tiktoken as follows: 0xE2 to [2928]
   870→            // and 0xAD, 0x90 to [99834]. Decoding 2928 and 99834 individually won't reconstruct the original UTF-16 string '⭐' U-2B50;
   871→            // decoding all IDs together is required to get the expected result.
   872→            if (ids is null)
   873→            {
   874→                throw new ArgumentNullException(nameof(ids));
   875→            }
   876→
   877→            // should be far enough to store incomplete utf-8 sequences
   878→            Span<byte> utf8Bytes = stackalloc byte[256];
   879→            // should be far enough to store one vocabulary token at time
   880→            Span<char> tempBuffer = stackalloc char[256];
   881→
   882→            int utf8BytesIncompleteCount = 0;
   883→            int utf8BytesIncompleteIndex = 0;
   884→            int incompleteCharsWritten = 0;
   885→            int hangingIdsCount = 0;
   886→
   887→            Span<char> buffer = destination;
   888→
   889→            foreach (int id in ids)
   890→            {
   891→                if (_decoder.TryGetValue(id, out ReadOnlyMemory<byte> tokenBytes))
   892→                {
   893→                    if (utf8BytesIncompleteCount + tokenBytes.Length > utf8Bytes.Length)
   894→                    {
   895→                        // Its unexpected to have a token that is larger than the utf8Bytes buffer.
   896→                        return OperationStatus.InvalidData;
   897→                    }
   898→
   899→                    if (Encoding.UTF8.GetMaxCharCount(utf8BytesIncompleteCount + tokenBytes.Length) > tempBuffer.Length)
   900→                    {
   901→                        return OperationStatus.DestinationTooSmall;
   902→                    }
   903→
   904→                    if (utf8BytesIncompleteCount == 0)
   905→                    {
   906→                        // No incomplete utf-8 sequence currently recorded. Try to decode tokenBytes directly.
   907→
   908→                        Debug.Assert(incompleteCharsWritten == 0);
   909→                        Debug.Assert(hangingIdsCount == 0);
   910→                        Debug.Assert(utf8BytesIncompleteIndex == 0);
   911→
   912→                        if (!Helpers.ConvertUtf8ToUtf16(tokenBytes.Span, tempBuffer, out int bytesConsumed, out incompleteCharsWritten))
   913→                        {
   914→                            return OperationStatus.InvalidData;
   915→                        }
   916→
   917→                        if (incompleteCharsWritten > buffer.Length)
   918→                        {
   919→                            return OperationStatus.DestinationTooSmall;
   920→                        }
   921→
   922→                        tempBuffer.Slice(0, incompleteCharsWritten).CopyTo(buffer);
   923→                        buffer = buffer.Slice(incompleteCharsWritten);
   924→
   925→                        if (bytesConsumed == tokenBytes.Length)
   926→                        {
   927→                            // Encoding is complete
   928→                            charsWritten += incompleteCharsWritten;
   929→                            idsConsumed++;
   930→                            incompleteCharsWritten = 0;
   931→                        }
   932→                        else
   933→                        {
   934→                            // Encoding is incomplete
   935→                            utf8BytesIncompleteCount = tokenBytes.Length - bytesConsumed;
   936→                            tokenBytes.Span.Slice(bytesConsumed).CopyTo(utf8Bytes);
   937→                            hangingIdsCount = 1;
   938→                        }
   939→                    }
   940→                    else
   941→                    {
   942→                        // Previously, we had an incomplete utf-8 sequence. Try to complete it first.
   943→                        tokenBytes.Span.CopyTo(utf8Bytes.Slice(utf8BytesIncompleteIndex + utf8BytesIncompleteCount));
   944→
   945→                        if (!Helpers.ConvertUtf8ToUtf16(utf8Bytes.Slice(utf8BytesIncompleteIndex, utf8BytesIncompleteCount + tokenBytes.Length), tempBuffer, out int bytesConsumed, out int charsConsumed))
   946→                        {
   947→                            return OperationStatus.InvalidData;
   948→                        }
   949→
   950→                        if (charsConsumed > buffer.Length)
   951→                        {
   952→                            return OperationStatus.DestinationTooSmall;
   953→                        }
   954→
   955→                        tempBuffer.Slice(0, charsConsumed).CopyTo(buffer);
   956→                        buffer = buffer.Slice(charsConsumed);
   957→
   958→                        if (bytesConsumed == utf8BytesIncompleteCount + tokenBytes.Length)
   959→                        {
   960→                            // Encoding is complete
   961→                            charsWritten += charsConsumed + incompleteCharsWritten;
   962→                            idsConsumed += hangingIdsCount + 1;
   963→                            hangingIdsCount = 0;
   964→                            utf8BytesIncompleteCount = 0;
   965→                            utf8BytesIncompleteIndex = 0;
   966→                            incompleteCharsWritten = 0;
   967→                        }
   968→                        else
   969→                        {
   970→                            // Encoding is incomplete
   971→                            utf8BytesIncompleteIndex += bytesConsumed;
   972→                            utf8BytesIncompleteCount = utf8BytesIncompleteCount + tokenBytes.Length - bytesConsumed;
   973→                            hangingIdsCount++;
   974→                            incompleteCharsWritten += charsConsumed;
   975→                        }
   976→                    }
   977→                }
   978→                else
   979→                {
   980→                    return OperationStatus.InvalidData;
   981→                }
   982→            }
   983→
   984→            return utf8BytesIncompleteCount != 0 ? OperationStatus.NeedMoreData : OperationStatus.Done;
   985→        }
