   700→        public void TestPreciseTokenLimits(string text, string[] expectedTokens, (int Index, int Length)[] expectedOffsets, int[] expectedIds)
   701→        {
   702→            IReadOnlyList<EncodedToken> result = GPT4.EncodeToTokens(text, out _);
   703→            int[] ids = result.Select(r => r.Id).ToArray();
   704→            (int Index, int Length)[] offsets = result.Select(r => (r.Offset.Start.Value, r.Offset.End.Value - r.Offset.Start.Value)).ToArray();
   705→            Assert.Equal(expectedTokens, result.Select(r => r.Value));
   706→            Assert.Equal(expectedIds, ids);
   707→            Assert.Equal(expectedOffsets, offsets);
   708→            Assert.Equal(expectedIds, GPT4.EncodeToIds(text));
   709→            Assert.Equal(expectedIds.Length, GPT4.CountTokens(text));
   710→
   711→            for (int tokenCount = 1; tokenCount <= ids.Length; tokenCount++)
   712→            {
   713→                int length = GPT4.GetIndexByTokenCount(text, tokenCount, out _, out int count);
   714→                Assert.True(count <= ids.Length);
   715→
   716→                if (count < tokenCount)
   717→                {
   718→                    Assert.True(count < ids.Length - 1);
   719→                    Assert.True(offsets[count + 1].Index < offsets[count].Index + offsets[count].Length);
   720→                }
   721→
   722→                if (count > 0)
   723→                {
   724→                    Assert.Equal(offsets[count - 1].Index + offsets[count - 1].Length, length);
   725→                }
   726→                else
   727→                {
   728→                    Assert.Equal(0, length);
   729→                }
   730→
   731→                int index = GPT4.GetIndexByTokenCountFromEnd(text, tokenCount, out _, out count);
   732→                Assert.True(count <= ids.Length);
   733→
   734→                if (count < tokenCount)
   735→                {
   736→                    Assert.True(ids.Length - tokenCount > 0);
   737→                    Assert.True(offsets[offsets.Length - tokenCount].Index < offsets[offsets.Length - tokenCount - 1].Index + offsets[offsets.Length - tokenCount - 1].Length);
   738→                }
   739→
   740→                if (count > 0)
   741→                {
   742→                    Assert.Equal(offsets[offsets.Length - count].Index, index);
   743→                }
   744→                else
   745→                {
   746→                    Assert.Equal(text.Length, index);
   747→                }
   748→            }
   749→        }
