        /// </summary>
        internal IReadOnlyDictionary<ReadOnlyMemory<byte>, int> Encoder => _encoder;

        /// <summary>
        /// Gets the dictionary mapping Ids to token utf-8 bytes.
        /// </summary>
        internal IReadOnlyDictionary<int, ReadOnlyMemory<byte>> Decoder => _decoder;

