private static Dictionary<string, int> GetO200kHarmonySpecialTokens()
{
    // Based on https://github.com/openai/tiktoken/blob/main/tiktoken_ext/openai_public.py
    // Encoding name: o200k_harmony
    Dictionary<string, int> specialTokens = new(StringComparer.Ordinal)
    {
        { StartOfText, 199998 },
        { EndOfText, 199999 },

        { "<|return|>", 200002 },
