        private static readonly ConcurrentDictionary<string, (Dictionary<ReadOnlyMemory<byte>, int> encoder, Dictionary<StringSpanOrdinalKey, (int Id, string Token)> vocab, Dictionary<int, ReadOnlyMemory<byte>> decoder)> _tiktokenCache = new(StringComparer.OrdinalIgnoreCase);

        private static Dictionary<string, int> GetO200kHarmonySpecialTokens()
        {
            // Based on https://github.com/openai/tiktoken/blob/main/tiktoken_ext/openai_public.py
            // Encoding name: o200k_harmony
            Dictionary<string, int> specialTokens = new(StringComparer.Ordinal)
            {
                { StartOfText, 199998 },
                { EndOfText, 199999 },

                { "<|return|>", 200002 },
                { "<|constrain|>", 200003 },
                { "<|channel|>", 200005 },
                { "<|start|>", 200006 },
                { "<|end|>", 200007 },
                { "<|message|>", 200008 },
                { "<|call|>", 200012 },

                // Keep parity with o200k_base configuration used in this codebase.
                { EndOfPrompt, 200018 },
            };

            // Reserved tokens.
            specialTokens["<|reserved_200000|>"] = 200000;
            specialTokens["<|reserved_200001|>"] = 200001;
            specialTokens["<|reserved_200004|>"] = 200004;
            specialTokens["<|reserved_200009|>"] = 200009;
            specialTokens["<|reserved_200010|>"] = 200010;
            specialTokens["<|reserved_200011|>"] = 200011;

            for (int i = 200013; i <= 201087; i++)
            {
                specialTokens[$"<|reserved_{i}|>"] = i;
            }

            return specialTokens;
        }

