            Assert.NotNull(tokenizer.PreTokenizer);

            // "o200k_harmony" shares the same mergeable ranks / data file as "o200k_base",
            // but has a different special-token mapping.
            if (encodingName.Equals("o200k_harmony", StringComparison.OrdinalIgnoreCase))
